import React, { useState, useEffect, useContext, useCallback } from 'react';
import {
	Container,
	Box,
	Typography,
	Card,
	CardContent,
	CircularProgress,
	Alert,
	Grid,
} from '@mui/material';
import { AuthContext } from '../context/AuthContext';
import api from '../api';
import KanbanBoard from '../components/KanbanBoard';

export default function EmployeeDashboard() {
	const { user } = useContext(AuthContext);
	const [tasks, setTasks] = useState([]);
	const [progressions, setProgressions] = useState([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState('');

	const fetchData = useCallback(async () => {
		setLoading(true);
		try {
			const [proRes, taskRes] = await Promise.all([
				api.get('/task-progressions'),
				api.get(`/my-tasks/${user?.id}`),
			]);

			const progBody = proRes.data;
			const progList = Array.isArray(progBody) ? progBody : (progBody.progressions ?? progBody.data ?? []);
			setProgressions(progList || []);

			const taskBody = taskRes.data;
			const taskList = Array.isArray(taskBody) ? taskBody : (taskBody.tasks ?? taskBody.data ?? []);
			setTasks(taskList || []);

			setError('');
		} catch (err) {
			console.error('Failed to load data', err);
			setError('Failed to load tasks');
		} finally {
			setLoading(false);
		}
	}, [user?.id]);

	useEffect(() => {
		if (user?.id) {
			fetchData();
		}
	}, [user?.id, fetchData]);

	const getTaskStats = () => {
		return {
			pending: tasks.filter((t) => !t.progression_step && t.status === 'pending').length,
			in_progress: tasks.filter((t) => !t.progression_step && t.status === 'in_progress').length,
			completed: tasks.filter((t) => !t.progression_step && t.status === 'completed').length,
		};
	};

	const getColumns = () => {
		const allColumns = [];

		// Add custom progression columns sorted by progression sort_order
		progressions
			.sort((a, b) => a.sort_order - b.sort_order)
			.forEach((prog) => {
				prog.steps
					.sort((a, b) => a.sort_order - b.sort_order)
					.forEach((step) => {
						allColumns.push({
							id: step.id,
							name: step.name,
							progressionName: prog.name,
							progressionId: prog.id,
							sortOrder: step.sort_order,
						});
					});
			});

		return allColumns;
	};

	const getTasksByColumn = () => {
		const cols = getColumns();
		const map = {};

		cols.forEach((c) => (map[c.id] = []));

		tasks.forEach((task) => {
			if (task.progression) {
				// Custom progression tasks
				const stepId = task.progression_step?.id;
				if (map[stepId]) map[stepId].push(task);
				else if (cols.length > 0) {
					// Find first step of this progression and add there
					const firstStep = task.progression.steps?.[0];
					if (firstStep && map[firstStep.id]) map[firstStep.id].push(task);
				}
			}
		});

		return map;
	};

	const handleMoveTask = async (taskId, info) => {
		try {
			const column = info.column;
			// All columns are progression step ids
			await api.patch(`/tasks/${taskId}/status`, { task_progression_step_id: column });
			await fetchData();
		} catch (err) {
			console.error('Failed to move task', err);
		}
	};

	const handleReorderColumns = async (sourceIndex, destIndex, progressionId) => {
		try {
			// Get all progressions sorted by their current sort_order
			const sortedProgs = progressions.sort((a, b) => a.sort_order - b.sort_order);

			// Clone array and perform reorder
			const reordered = [...sortedProgs];
			const [movedProg] = reordered.splice(sourceIndex, 1);
			reordered.splice(destIndex, 0, movedProg);

			// Create payload with ALL progressions in new order
			const payload = {
				progressions: reordered.map((prog, index) => ({
					id: prog.id,
					sort_order: index + 1,
				})),
			};

			await api.post('/task-progressions/reorder', payload);

			// Update local state immediately for instant UI feedback
			setProgressions(reordered.map((prog, index) => ({
				...prog,
				sort_order: index + 1,
			})));
		} catch (err) {
			console.error('Failed to reorder columns', err);
			// Revert by fetching fresh data on error
			await fetchData();
		}
	};

	const stats = getTaskStats();

	return (
		<Box sx={{ backgroundColor: '#F8FAFC', minHeight: 'calc(100vh - 64px)', py: 4 }}>
			<Container maxWidth="xl">
				<Box sx={{ mb: 6 }}>
					<Typography variant="h3" sx={{ fontWeight: 800, mb: 1, color: '#0F172A' }}>
						My Tasks
					</Typography>
					<Typography variant="body1" sx={{ color: '#64748B' }}>
						Track and manage your assigned work
					</Typography>
				</Box>

				<Grid container spacing={3} sx={{ mb: 4 }}>
					{[
						{ label: 'To Do', value: stats.pending, color: '#FEF3C7', textColor: '#92400E' },
						{ label: 'In Progress', value: stats.in_progress, color: '#E0F2FE', textColor: '#0369A1' },
						{ label: 'Done', value: stats.completed, color: '#DCFCE7', textColor: '#065F46' },
					].map((stat) => (
						<Grid item xs={12} sm={6} md={3} key={stat.label}>
							<Card sx={{ 
								border: '1px solid #E2E8F0', 
								borderLeft: `4px solid ${stat.textColor}`,
								backgroundColor: stat.color,
								transition: 'transform 0.2s',
								'&:hover': { transform: 'translateY(-2px)' }
							}}>
								<CardContent sx={{ textAlign: 'center' }}>
									<Typography variant="h3" sx={{ color: stat.textColor, fontWeight: 700, mb: 1 }}>
										{stat.value}
									</Typography>
									<Typography variant="body2" sx={{ color: stat.textColor }}>
										{stat.label}
									</Typography>
								</CardContent>
							</Card>
						</Grid>
					))}
				</Grid>

				{error && (
					<Alert severity="error" sx={{ mb: 4, borderRadius: 2 }}>
						{error}
					</Alert>
				)}

				{loading ? (
					<Box sx={{ display: 'flex', justifyContent: 'center', py: 6 }}>
						<CircularProgress />
					</Box>
				) : tasks.length === 0 ? (
					<Card sx={{ backgroundColor: '#fff', border: '1px solid #E2E8F0', textAlign: 'center', py: 6 }}>
						<Typography variant="h6" sx={{ color: '#0F172A', mb: 1 }}>
							No tasks assigned yet
						</Typography>
						<Typography variant="body2" sx={{ color: '#64748B' }}>
							Check back soon for new assignments from your team lead.
						</Typography>
					</Card>
				) : (
					<Box>
						<KanbanBoard
							columns={getColumns()}
							tasksByColumn={getTasksByColumn()}
							currentUser={user}
							canDragTask={(task, currentUser) => task.assigned_users?.some((u) => u.id === currentUser?.id)}
							onMoveTask={handleMoveTask}
							onReorderColumns={handleReorderColumns}
						/>
					</Box>
				)}
			</Container>
		</Box>
	);
}
